// ============================================================
// SIEM-001 — Détecteur Brute Force AFD
// VERSION CORRIGÉE FINALE — headers token fix
// ============================================================

const raw  = $input.first().json;
const body = raw.body || raw;
const now  = Date.now();
const ts   = new Date().toISOString();

// ── TOKEN — lecture headers HTTP EN PRIORITÉ ──────────────
const receivedToken = String(
  (raw.headers && raw.headers['x-soc-token']) ||
  (raw.headers && raw.headers['X-Soc-Token']) ||
  raw['x-soc-token']  ||
  raw.soc_token       ||
  body['x-soc-token'] ||
  body.soc_token      || ''
).trim();

const SOC_TOKEN = String($vars.SIEM_TOKEN || '').trim();

if (!receivedToken) {
  return [{ json: { error: 'UNAUTHORIZED',
    message: 'Token manquant', timestamp: ts } }];
}
if (!SOC_TOKEN) {
  return [{ json: { error: 'MISCONFIGURATION',
    message: 'Variable SIEM_TOKEN non configurée dans n8n Settings',
    timestamp: ts } }];
}
if (receivedToken !== SOC_TOKEN) {
  console.log('[SECURITY][SIEM-001] Token invalide — ' + ts);
  return [{ json: { error: 'UNAUTHORIZED',
    message: 'Token SOC invalide — SIEM-001', timestamp: ts } }];
}

// ── HELPERS ────────────────────────────────────────────────
function sanitizeForLog(val) {
  return String(val).replace(/[|\n\r\t]/g, '_').substring(0, 100);
}

function normalizeIP(raw_ip) {
  const s = String(raw_ip || '').trim().toLowerCase();
  if (s.startsWith('::ffff:')) return s.slice(7);
  if (/^(\d{1,3}\.){3}\d{1,3}$/.test(s)) {
    const octets = s.split('.').map(Number);
    if (octets.some(o => isNaN(o) || o < 0 || o > 255)) return null;
    return octets.join('.');
  }
  if (/^[0-9a-f:]{3,39}$/.test(s)) return s;
  return null;
}

function getMitreEnriched(type, context) {
  const TACTIC_MAP = {
    auth_fail      : 'Credential Access',
    port_scan      : 'Discovery',
    priv_escalation: 'Privilege Escalation',
    phishing       : 'Initial Access',
    data_exfil     : 'Exfiltration'
  };
  const MITRE_DB = {
    auth_fail: [
      { sub: 'T1110.003', name: 'Password Spraying',
        condition: c => c.multi_user === true },
      { sub: 'T1110.004', name: 'Credential Stuffing',
        condition: c => (c.fail_count || 0) >= 10 },
      { sub: 'T1110.001', name: 'Password Guessing',
        condition: () => true },
    ],
    phishing: [
      { sub: 'T1566.001', name: 'Spearphishing Attachment',
        condition: c => c.has_attachment === true },
      { sub: 'T1566.002', name: 'Spearphishing Link',
        condition: c => c.has_link === true },
      { sub: 'T1566', name: 'Phishing', condition: () => true },
    ],
    port_scan:       [{ sub: 'T1046', name: 'Network Service Discovery', condition: () => true }],
    priv_escalation: [{ sub: 'T1068', name: 'Exploitation for Priv Esc', condition: () => true }],
    data_exfil: [
      { sub: 'T1048', name: 'Exfil Over Alt Protocol',
        condition: c => ['dns','icmp','ftp'].includes(c.protocol) },
      { sub: 'T1041', name: 'Exfil Over C2 Channel', condition: () => true },
    ]
  };
  const tactic     = TACTIC_MAP[type] || 'Unknown';
  const candidates = MITRE_DB[type]   || [];
  const match      = candidates.find(c => c.condition(context));
  return {
    tactic,
    technique: match ? match.sub  : 'T0000',
    name     : match ? match.name : type
  };
}

// ── VALIDATION INPUTS ──────────────────────────────────────
const type = String(body.type || 'unknown').toLowerCase().trim();
const user = String(body.user || 'unknown').trim();
const ip   = normalizeIP(body.ip || body.source_ip || '');

if (!ip) {
  return [{ json: { error: 'INVALID_IP',
    message: 'Format IP invalide: ' + sanitizeForLog(String(body.ip || '')),
    timestamp: ts } }];
}

const VALID_TYPES = [
  'auth_fail','port_scan','priv_escalation','phishing','data_exfil','resolved','reset'
];
if (!VALID_TYPES.includes(type)) {
  return [{ json: { error: 'INVALID_TYPE',
    received: sanitizeForLog(type), timestamp: ts } }];
}

// ── SLIDING WINDOW RATE-LIMITING ───────────────────────────
const store  = $getWorkflowStaticData('global');
const safeIP = ip.replace(/[.:]/g, '_');
const rlKey  = 'RL_' + safeIP;
let rl = { timestamps: [] };
try { rl = JSON.parse(store[rlKey] || '{}'); } catch(e) {}

const WINDOW_MS = 60000;
const MAX_REQS  = 60;
const cutoff    = now - WINDOW_MS;
rl.timestamps   = (rl.timestamps || []).filter(t => t > cutoff);

if (rl.timestamps.length >= MAX_REQS) {
  const retryAfter = Math.ceil((rl.timestamps[0] + WINDOW_MS - now) / 1000);
  return [{ json: { error: 'RATE_LIMITED', ip,
    message: 'Limite ' + MAX_REQS + ' req/min atteinte',
    retry_after: retryAfter + 's', timestamp: ts } }];
}
rl.timestamps.push(now);
store[rlKey] = JSON.stringify(rl);

// ── FSM DEPUIS SUPABASE ────────────────────────────────────
const dbRow = $('DB_LoadFSM').first()?.json;
let fsm = null;
if (dbRow && dbRow.state) {
  const age = now - new Date(dbRow.last_seen).getTime();
  if (age < 600000) {
    fsm = {
      state    : dbRow.state,
      counter  : dbRow.counter,
      sessionId: dbRow.session_id,
      alertSent: dbRow.alert_sent,
      lastTs   : new Date(dbRow.last_seen).getTime()
    };
  }
}
if (!fsm) {
  fsm = {
    state    : 'q0',
    counter  : 0,
    lastTs   : now,
    sessionId: 'SESS_' + now,
    alertSent: false
  };
}

// ── SEVERITY MAP ───────────────────────────────────────────
const SEVERITY_MAP = {
  q0: { level: 'INFO',     score: 0,   priority: 'P4' },
  q1: { level: 'LOW',      score: 25,  priority: 'P3' },
  q2: { level: 'MEDIUM',   score: 50,  priority: 'P2' },
  q3: { level: 'HIGH',     score: 75,  priority: 'P1' },
  q4: { level: 'CRITICAL', score: 100, priority: 'P0' }
};

// ── RESET ──────────────────────────────────────────────────
if (type === 'resolved' || type === 'reset') {
  return [{ json: {
    session_id     : fsm.sessionId,
    ip, source_ip  : ip,
    event_type     : type,
    state_after    : 'q0',
    alerte         : false,
    alert_triggered: false,
    message        : 'FSM reset pour IP ' + sanitizeForLog(ip),
    timestamp      : ts,
    incident_type  : 'brute_force',
    _fsm_reset     : true
  }}];
}

const stateBefore = fsm.state;

// ── TABLE FSM ──────────────────────────────────────────────
const FSM_TABLE = {
  q0: {
    auth_fail: () => { fsm.counter++; return fsm.counter >= 3 ? 'q1' : 'q0'; }
  },
  q1: {
    auth_fail      : () => { fsm.counter = Math.min(fsm.counter + 1, 9999); return 'q1'; },
    port_scan      : () => 'q2',
    priv_escalation: () => 'q3',
    phishing       : () => 'q3',
    data_exfil     : () => 'q3',
    timeout        : () => { fsm.counter = 0; return 'q0'; }
  },
  q2: {
    priv_escalation: () => 'q3',
    data_exfil     : () => 'q3',
    phishing       : () => 'q3',
    timeout        : () => { fsm.counter = 0; return 'q0'; }
  },
  q3: {
    data_exfil     : () => { fsm.alertSent = false; return 'q4'; },
    priv_escalation: () => 'q4',
    timeout        : () => { fsm.counter = 0; fsm.alertSent = false; return 'q0'; },
    resolved       : () => { fsm.counter = 0; fsm.alertSent = false; return 'q0'; }
  },
  q4: {
    data_exfil     : () => { fsm.alertSent = false; return 'q4'; },
    priv_escalation: () => { fsm.alertSent = false; return 'q4'; },
    auth_fail      : () => 'q4',
    timeout        : () => { fsm.counter = 0; fsm.alertSent = false; return 'q0'; },
    resolved       : () => { fsm.counter = 0; fsm.alertSent = false; return 'q0'; }
  }
};

let stateAfter = fsm.state;
if (FSM_TABLE[fsm.state]?.[type]) {
  stateAfter = FSM_TABLE[fsm.state][type]();
}
fsm.state = stateAfter;

let shouldAlert = false;
if ((stateAfter === 'q3' || stateAfter === 'q4') && !fsm.alertSent) {
  shouldAlert   = true;
  fsm.alertSent = true;
}
if (stateAfter !== 'q3' && stateAfter !== 'q4') fsm.alertSent = false;
fsm.lastTs = now;

// ── MITRE + SEVERITY ───────────────────────────────────────
const mitreContext = {
  fail_count    : fsm.counter,
  multi_user    : body.multi_user     || false,
  has_attachment: body.has_attachment || false,
  has_link      : body.has_link       || false,
  protocol      : body.protocol       || 'unknown'
};
const mitre    = getMitreEnriched(type, mitreContext);
const severity = SEVERITY_MAP[stateAfter] || SEVERITY_MAP.q0;

return [{ json: {
  session_id     : fsm.sessionId,
  ip,
  source_ip      : ip,
  user           : sanitizeForLog(user),
  username       : sanitizeForLog(user),
  event_type     : type,
  timestamp      : ts,
  state_before   : stateBefore,
  state_after    : stateAfter,
  etat_apres     : stateAfter,
  auth_fail_count: fsm.counter,
  alert_sent     : fsm.alertSent,
  mitre_tactic   : mitre.tactic,
  mitre_tech     : mitre.technique,
  mitre_name     : mitre.name,
  severity       : severity.level,
  severity_score : severity.score,
  priority       : severity.priority,
  alerte         : shouldAlert,
  alert_triggered: shouldAlert,
  incident_type  : 'brute_force'
}}];
